(ns agent-loop.tools)


;; --- shared_logic: tools (generated from compile_logic) ---

(defn is-destructive
  "Check if a tool name is in the destructive set (bash, write, edit)."
  [tool-name]
  (#{"bash" "write" "edit"} tool-name)
)

(defn is-safe
  "Check if a tool is read-only (safe without approval)."
  [tool-name]
  (= tool-name "read")
)

(defn is-approved
  "Check if a tool is in the user-approved set."
  [tool-name approved-set]
  (contains? approved-set tool-name)
)

(defn tool-needs-approval
  "Check if a tool requires user approval (destructive and not safe)."
  [tool-name]
  (if (= tool-name "read")
      false
      (#{"bash" "write" "edit"} tool-name)
  )
)

(defn check-approval-block
  "Return true if tool should be blocked: destructive + not in approved set."
  [tool-name approved-set]
  (if (not (#{"bash" "write" "edit"} tool-name))
      false
      (not (contains? approved-set tool-name))
  )
)

(defn is-mcp-tool
  "Check if tool name has mcp: prefix indicating MCP dispatch."
  [tool-name]
  (.startsWith tool-name "mcp:")
)

(defn has-required-params
  "Check that all required parameter keys exist in args dict."
  [args required-keys]
  (every? #(contains? args %) required-keys)
)

(defn tool-category
  "Categorize a tool as destructive, safe, or normal."
  [tool-name]
  (if (#{"bash" "write" "edit"} tool-name)
      "destructive"
      (if (= tool-name "read")
          "safe"
          "normal"
      )
  )
)

(defn is-builtin
  "Check if a tool name refers to a built-in (non-MCP) tool."
  [tool-name]
  (not (.startsWith tool-name "mcp__"))
)

(defn needs-path-validation
  "Check if a tool requires file path validation (read, write, or edit)."
  [tool-name]
  (or (.startsWith tool-name "read") (or (.startsWith tool-name "write") (.startsWith tool-name "edit")))
)

(defn arg-count
  "Return the number of arguments a tool accepts. Returns 0 if tool not found."
  [state tool-name]
  (int (count (:args state)))
)

(defn has-schema
  "Check if a tool has a JSON schema definition for its parameters."
  [state tool-name]
  (> (count (:schema state)) 0)
)

(defn name-is-valid
  "Check if a tool name is non-empty."
  [tool-name]
  (> (count tool-name) 0)
)

(defn is-mcp-prefixed
  "Check if a tool name has the mcp: namespace prefix."
  [name]
  (.startsWith name "mcp:")
)

(defn is-readonly
  "Check if a tool is read-only (read or glob)."
  [tool-name]
  (or (= tool-name "read") (= tool-name "glob"))
)

